# Category: insecure_jwt

from flask import Flask, request, jsonify, g
from werkzeug.security import generate_password_hash, check_password_hash
import jwt
import datetime
import functools
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'change_this_secret')

# In-memory user store (username -> password_hash)
USERS = {
    'admin': generate_password_hash('admin123')
}

def create_token(username):
    payload = {
        'sub': username,
        'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=1)
    }
    return jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')

def token_required(f):
    @functools.wraps(f)
    def wrapper(*args, **kwargs):
        auth = request.headers.get('Authorization', None)
        if not auth or not auth.startswith('Bearer '):
            return jsonify({'message': 'token missing'}), 401
        token = auth.split()[1]
        try:
            data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
            g.current_user = data['sub']
        except jwt.ExpiredSignatureError:
            return jsonify({'message': 'token expired'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'message': 'invalid token'}), 401
        return f(*args, **kwargs)
    return wrapper

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json(True)
    username = data.get('username')
    password = data.get('password')
    if not username or not password:
        return jsonify({'message': 'username and password required'}), 400
    if username in USERS:
        return jsonify({'message': 'user exists'}), 409
    USERS[username] = generate_password_hash(password)
    return jsonify({'message': 'registered'}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json(True)
    username = data.get('username')
    password = data.get('password')
    if username not in USERS or not check_password_hash(USERS[username], password):
        return jsonify({'message': 'invalid credentials'}), 401
    token = create_token(username)
    return jsonify({'token': token})

@app.route('/protected')
@token_required
def protected():
    return jsonify({'message': f'hello, {g.current_user}'})

if __name__ == '__main__':
    app.run(debug=True)